mapper.update:
update mcp_servers
set name = #{name}, transport = #{transport},
    command = #{command}, args = #{args}, env_vars = #{envVars},
    url = #{url}, headers = #{headers},
    updated_at = #{updatedAt}
where id = #{id} and user_name = #{userName}

update mcp_tools
set tool_name = #{toolName}, description = #{description}
where id = #{id} and user_name = #{userName}
